#include <stdio.h>
#include <math.h>

int main() {
    int n;
    scanf("%d", &n);
    int factors[100][2];
    int count = 0;
    int value = n;
    for (int divisor = 2; divisor <= n; divisor++) {
        if (value % divisor == 0) {
            int exponent = 0;
            while (value % divisor == 0) {
                exponent++;
                value /= divisor;
            }
            factors[count][0] = divisor;
            factors[count][1] = exponent;
            count++;
        }
    }
    int product = 1;
    int max_exp_two = 0;
    for (int i = 0; i < count; i++) {
        product *= factors[i][0];
        int exponent = factors[i][1];
        int power_two = (int)(log2(exponent));
        if (exponent > (1 << power_two)) {
            power_two++;
        }
        if (power_two > max_exp_two) {
            max_exp_two = power_two;
        }
    }
    int needs_adjustment = 0;
    for (int i = 0; i < count; i++) {
        if (factors[i][1] < (1 << max_exp_two)) {
            needs_adjustment = 1;
        }
    }
    printf("%d %d\n", product, max_exp_two + needs_adjustment);
    return 0;
}
